    #[test]
    fn typed_offset_plane_reference_accepts_principal_and_feature_targets() {
        let record = |source: u32, signature: [u8; 4], selector: u32| {
            let mut bytes = Vec::new();
            bytes.extend(source.to_le_bytes());
            bytes.extend(signature);
            bytes.extend([0; 2]);
            bytes.extend(selector.to_le_bytes());
            bytes.extend(1u32.to_le_bytes());
            bytes.extend([0; 4]);
            bytes.extend(247u32.to_le_bytes());
            bytes.extend([0; 12]);
            bytes.extend([0xc7, 0xcf, 0xff, 0xff, 0xc7, 0xcf, 0xff, 0xff]);
            bytes
        };
        let known = HashSet::from([3, 225]);
        let principal = record(3, [0x79, 0x2a, 0xe1, 0x3b], 2);
        assert_eq!(
            offset_plane_reference_source(&principal, &known, None),
            Some(3)
        );
        let feature = record(225, [0x30, 0x92, 0xab, 0x53], 0);
        assert_eq!(
            offset_plane_reference_source(&feature, &known, None),
            Some(225)
        );
        assert_eq!(
            offset_plane_reference_source(&feature, &known, Some(225)),
            None
        );

        let mut ambiguous = principal;
        ambiguous.extend(feature);
        assert_eq!(
            offset_plane_reference_source(&ambiguous, &known, None),
            None
        );
        ambiguous[38] ^= 1;
        assert_eq!(
            offset_plane_reference_source(&ambiguous, &known, None),
            Some(225)
        );
    }

    #[test]
    fn compact_profile_uses_a_unique_lane_scoped_reference_plane() {
        let mut payload = b"moCompRefPlane_c".to_vec();
        payload.extend([0; 11]);
        payload.extend(2u32.to_le_bytes());
        payload.extend(19u32.to_le_bytes());
        payload.extend([0, 0, 3, 0]);
        payload.extend([0; 27]);
        payload.extend(1.0f64.to_le_bytes());
        payload.extend([
            0x00, 0x00, 0x00, 0x04, 0x00, 0x00, 0x00, 0xf9, 0xff, 0xff, 0xff, 0x00, 0x00, 0x00,
            0x00, 0x65,
        ]);
        payload.extend([0; 80]);
        let component_start = payload.len();
        let mut component = [0u8; 138];
        component[..4].copy_from_slice(&549u32.to_le_bytes());
        component[14] = 1;
        for (offset, value) in [
            (15, 1.0),
            (23, 0.0),
            (31, 0.0),
            (39, 0.0),
            (47, 1.0),
            (55, 0.0),
            (63, 0.0),
            (71, 0.0),
            (79, 1.0),
        ] {
            component[offset..offset + 8].copy_from_slice(&f64::to_le_bytes(value));
        }
        component[122..126].copy_from_slice(&4u32.to_le_bytes());
        component[126..130].fill(0xff);
        payload.extend(component);
        let profile_start = payload.len();
        payload.extend([0xaa; 64]);

        assert_eq!(
            compact_profile_reference_plane_source(
                &payload,
                profile_start,
                profile_start,
                payload.len(),
            ),
            Some(2)
        );
        assert_eq!(
            compact_profile_reference_plane_source(
                &payload,
                component_start,
                component_start,
                payload.len(),
            ),
            Some(549)
        );
    }

