        payload.extend(9u32.to_le_bytes());
        payload.extend([0; 4]);
        payload.extend([0x34, 0x80, 1, 0, 56, 0, 0, 0, 2, 0, 0, 0]);
        payload.extend(4u32.to_le_bytes());

